class UnionFind:
    def __init__(self):
        self.parent = {}

    def find(self, i):
        if self.parent[i] == i:
            return i
        self.parent[i] = self.find(self.parent[i])
        return self.parent[i]

    def union(self, i, j):
        root_i = self.find(i)
        root_j = self.find(j)

        if root_i != root_j:
            self.parent[root_j] = root_i
            return True
        return False

def accountsMerge(accounts):
    uf = UnionFind()
    email_to_name = {}

    for account in accounts:
        name = account[0]
        for i in range(1, len(account)):
            email = account[i]
            if email not in uf.parent:
                uf.parent[email] = email
            email_to_name[email] = name

    for account in accounts:
        first_email = account[1]
        for i in range(2, len(account)):
            email = account[i]
            uf.union(first_email, email)

    merged_emails = {}
    for email in uf.parent:
        root = uf.find(email)
        if root not in merged_emails:
            merged_emails[root] = []
        merged_emails[root].append(email)

    result = []
    for root, emails_list in merged_emails.items():
        name = email_to_name[root]
        emails_list.sort()
        result.append([name] + emails_list)

    return result
